const all = $input.all().map(i => i.json);
const q = $items('Webhook List', 0, 0)[0]?.json?.query ?? {};

const toNull = (v) => (v === undefined || v === null || v === '' ? null : v);
const status = toNull(q.status);
const priority = toNull(q.priority);
const search = toNull(q.search);
const sort = ['created_at','priority','status','title'].includes(String(q.sort || '')) ? String(q.sort) : 'created_at';
const order = String(q.order || 'desc').toLowerCase() === 'asc' ? 'asc' : 'desc';

let filtered = all;
if (status) filtered = filtered.filter(t => t.status === status);
if (priority) filtered = filtered.filter(t => t.priority === priority);
if (search) filtered = filtered.filter(t => String(t.title || '').toLowerCase().includes(String(search).toLowerCase()));

const childCount = new Map();
for (const t of filtered) {
  if (t.parent_id) childCount.set(t.parent_id, (childCount.get(t.parent_id) || 0) + 1);
}

let roots = filtered
  .filter(t => t.parent_id === null)
  .map(t => ({ ...t, subtask_count: childCount.get(t.id) || 0 }));

const priorityRank = { low: 1, medium: 2, high: 3, urgent: 4 };
roots.sort((a, b) => {
  let av = a[sort];
  let bv = b[sort];
  if (sort === 'priority') { av = priorityRank[a.priority] ?? 0; bv = priorityRank[b.priority] ?? 0; }
  if (sort === 'created_at') { av = new Date(a.created_at).getTime(); bv = new Date(b.created_at).getTime(); }
  if (av < bv) return order === 'asc' ? -1 : 1;
  if (av > bv) return order === 'asc' ? 1 : -1;
  return 0;
});

const est = (v) => (v == null ? 0 : Number(v));
const stats = {
  todo_count: filtered.filter(t => t.status === 'todo').length,
  in_progress_count: filtered.filter(t => t.status === 'in_progress').length,
  done_count: filtered.filter(t => t.status === 'done').length,
  total_estimate: filtered.reduce((a,t) => a + est(t.estimate), 0),
  todo_estimate: filtered.filter(t => t.status === 'todo').reduce((a,t) => a + est(t.estimate), 0),
  in_progress_estimate: filtered.filter(t => t.status === 'in_progress').reduce((a,t) => a + est(t.estimate), 0),
};

return [{ json: { statusCode: 200, body: { data: roots, total: roots.length, stats } } }];
